import React, { useState } from 'react';
import '../styles/Volunteer.css';

const Volunteer = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    skills: '',
    availability: '',
    interests: [],
    message: ''
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prevState => ({
      ...prevState,
      [name]: value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Handle form submission here
    console.log('Form submitted:', formData);
  };

  const opportunities = [
    {
      title: 'Wildlife Conservation',
      description: 'Work directly with our wildlife conservation teams to protect endangered species.',
      icon: 'fas fa-paw'
    },
    {
      title: 'Community Education',
      description: 'Teach local communities about wildlife conservation and sustainable practices.',
      icon: 'fas fa-chalkboard-teacher'
    },
    {
      title: 'Research & Monitoring',
      description: 'Assist in wildlife research, data collection, and habitat monitoring.',
      icon: 'fas fa-microscope'
    },
    {
      title: 'Event Organization',
      description: 'Help organize conservation awareness events and fundraising activities.',
      icon: 'fas fa-calendar-alt'
    }
  ];

  return (
    <div className="volunteer-page">
      <div className="volunteer-hero">
        <h1>Join Our Volunteer Team</h1>
        <p>Make a difference in wildlife conservation</p>
      </div>

      <div className="volunteer-container">
        <div className="volunteer-info">
          <h2>Why Volunteer With Us?</h2>
          <div className="benefits-grid">
            <div className="benefit-card">
              <i className="fas fa-hands-helping"></i>
              <h3>Make an Impact</h3>
              <p>Directly contribute to wildlife conservation efforts</p>
            </div>
            <div className="benefit-card">
              <i className="fas fa-users"></i>
              <h3>Join a Community</h3>
              <p>Connect with like-minded conservationists</p>
            </div>
            <div className="benefit-card">
              <i className="fas fa-graduation-cap"></i>
              <h3>Learn & Grow</h3>
              <p>Gain valuable experience and knowledge</p>
            </div>
          </div>
        </div>

        <div className="volunteer-form">
          <h2>Volunteer Application</h2>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <input
                type="text"
                name="name"
                placeholder="Full Name"
                value={formData.name}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <input
                type="email"
                name="email"
                placeholder="Email Address"
                value={formData.email}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <input
                type="tel"
                name="phone"
                placeholder="Phone Number"
                value={formData.phone}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <input
                type="text"
                name="skills"
                placeholder="Skills & Experience"
                value={formData.skills}
                onChange={handleChange}
                required
              />
            </div>
            <div className="form-group">
              <select
                name="availability"
                value={formData.availability}
                onChange={handleChange}
                required
              >
                <option value="">Select Availability</option>
                <option value="full-time">Full Time</option>
                <option value="part-time">Part Time</option>
                <option value="weekends">Weekends Only</option>
                <option value="flexible">Flexible</option>
              </select>
            </div>
            <div className="form-group">
              <textarea
                name="message"
                placeholder="Why do you want to volunteer with us?"
                value={formData.message}
                onChange={handleChange}
                required
                rows="4"
              ></textarea>
            </div>
            <button type="submit" className="submit-btn">Submit Application</button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Volunteer;
